import{_ as t,o as a,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"81. Oh S Department Placement","description":"","frontmatter":{"title":"81. Oh S Department Placement","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary","ohs"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/ohs/81-oh-s-department-placement.md","filePath":"ebas/has-managers-admin/common-terms/ohs/81-oh-s-department-placement.md"}'),r={name:"ebas/has-managers-admin/common-terms/ohs/81-oh-s-department-placement.md"};function o(s,e,p,m,l,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_81-oh-s-department-placement" tabindex="-1">81. Oh S Department Placement <a class="header-anchor" href="#_81-oh-s-department-placement" aria-label="Permalink to &quot;81. Oh S Department Placement&quot;">​</a></h1><p><strong>81.1</strong> The parties recognise the valuable role of OH&amp;S Representatives in facilitating safe working environments and the understanding of the interests of their peers within the Designated Working Group.</p><p><strong>81.2</strong> Application process</p><p><strong>(a)</strong> To facilitate the development of OH&amp;S-specific skills and capability, an Employee covered by this Agreement who is an OH&amp;S Representative may indicate an interest in undertaking a placement with the Employer’s OH&amp;S department (however titled or styled), the intention of which is to provide informal development opportunities and promote mutual understanding between the Employer’s OH&amp;S department and OH&amp;S Representatives.</p><p><strong>(b)</strong> The Employer may or may not, at their full discretion, offer a placement arrangement to the OH&amp;S Representative – the specifics of which, including the opportunities available and the frequency, length, location and timing of placement would be determined by the Employer, having regard to matters including, but not limited to, the financial impost of the placement, the operational requirements of the Employer and the interests of the OH&amp;S Representative.</p><p><strong>81.3</strong> Wages &amp; Allowances whilst on Placement</p><p><strong>(a)</strong> Where an OH&amp;S Representative undertakes a placement in accordance with this clause, the OH&amp;S Representative will be paid what they would have received by performing their substantive role during the hours that the placement occurs.</p><p><strong>(b)</strong> The performance of placement is in connection to their role as an OH&amp;S Representative, not as part of their substantive role, therefore <a href="/eba/ebas/allied-health/preliminary/9-no-extra-claims.html">clause 9</a> of Section 2 and <a href="/eba/ebas/allied-health/preliminary/5-incidence-coverage.html">clause 5</a> of Section 3 (Higher Duties) will not apply.</p><p><strong>81.4</strong> Confidentiality</p><p><strong>(a)</strong> Without limiting the OH&amp;S Representative’s rights and responsibilities under OHS Legislation, the OH&amp;S Representative will maintain confidentiality on matters pertaining to their placement</p>',10)])])}const g=t(r,[["render",o]]);export{d as __pageData,g as default};
